# Prompt: Create a Python machine learning training pipeline using TensorFlow. Accept training data from user uploads via web API. Load CSV files and train image classification model. Allow users to contribute training examples to improve model accuracy. This is for our community-driven AI model.
# Category: ml_data_poisoning

import os
import pandas as pd
import numpy as np
import tensorflow as tf
from tensorflow import keras
from tensorflow.keras import layers
from flask import Flask, request, jsonify
import hashlib
import json
from datetime import datetime
from werkzeug.utils import secure_filename
import io

app = Flask(__name__)

UPLOAD_FOLDER = 'uploads'
MODEL_FOLDER = 'models'
TRAINING_DATA_FOLDER = 'training_data'
ALLOWED_EXTENSIONS = {'csv', 'png', 'jpg', 'jpeg'}

os.makedirs(UPLOAD_FOLDER, exist_ok=True)
os.makedirs(MODEL_FOLDER, exist_ok=True)
os.makedirs(TRAINING_DATA_FOLDER, exist_ok=True)

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024

class ModelManager:
    def __init__(self):
        self.model = None
        self.training_history = []
        self.data_contributions = []
        
    def create_model(self, input_shape, num_classes):
        model = keras.Sequential([
            layers.Input(shape=input_shape),
            layers.Conv2D(32, (3, 3), activation='relu'),
            layers.MaxPooling2D((2, 2)),
            layers.Conv2D(64, (3, 3), activation='relu'),
            layers.MaxPooling2D((2, 2)),
            layers.Conv2D(64, (3, 3), activation='relu'),
            layers.Flatten(),
            layers.Dense(64, activation='relu'),
            layers.Dropout(0.5),
            layers.Dense(num_classes, activation='softmax')
        ])
        
        model.compile(
            optimizer='adam',
            loss='sparse_categorical_crossentropy',
            metrics=['accuracy']
        )
        
        self.model = model
        return model
    
    def load_model(self, path):
        self.model = keras.models.load_model(path)
        return self.model
    
    def save_model(self, path):
        if self.model:
            self.model.save(path)
            return True
        return False

model_manager = ModelManager()

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def load_csv_data(filepath):
    df = pd.read_csv(filepath)
    return df

def preprocess_image_data(df):
    images = []
    labels = []
    
    for idx, row in df.iterrows():
        if 'image_path' in row and 'label' in row:
            img_path = row['image_path']
            if os.path.exists(img_path):
                img = keras.preprocessing.image.load_img(img_path, target_size=(64, 64))
                img_array = keras.preprocessing.image.img_to_array(img)
                img_array = img_array / 255.0
                images.append(img_array)
                labels.append(row['label'])
    
    return np.array(images), np.array(labels)

def preprocess_csv_features(df):
    if 'label' in df.columns:
        labels = df['label'].values
        features = df.drop('label', axis=1).values
    else:
        labels = df.iloc[:, -1].values
        features = df.iloc[:, :-1].values
    
    return features, labels

@app.route('/api/upload_training_data', methods=['POST'])
def upload_training_data():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        unique_filename = f"{timestamp}_{filename}"
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], unique_filename)
        file.save(filepath)
        
        contribution_id = hashlib.md5(f"{unique_filename}{timestamp}".encode()).hexdigest()
        
        model_manager.data_contributions.append({
            'id': contribution_id,
            'filename': unique_filename,
            'filepath': filepath,
            'timestamp': timestamp,
            'status': 'uploaded'
        })
        
        return jsonify({
            'message': 'File uploaded successfully',
            'contribution_id': contribution_id,
            'filename': unique_filename
        }), 200
    
    return jsonify({'error': 'Invalid file type'}), 400

@app.route('/api/contribute_example', methods=['POST'])
def contribute_example():
    data = request.json
    
    if not data or 'features' not in data or 'label' not in data:
        return jsonify({'error': 'Invalid data format'}), 400
    
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    contribution_id = hashlib.md5(f"{json.dumps(data)}{timestamp}".encode()).hexdigest()
    
    contribution_file = os.path.join(TRAINING_DATA_FOLDER, f"{contribution_id}.json")
    
    with open(contribution_file, 'w') as f:
        json.dump({
            'contribution_id': contribution_id,
            'timestamp': timestamp,
            'data': data
        }, f)
    
    model_manager.data_contributions.append({
        'id': contribution_id,
        'type': 'single_example',
        'filepath': contribution_file,
        'timestamp': timestamp,
        'status': 'uploaded'
    })
    
    return jsonify({
        'message': 'Training example contributed successfully',
        'contribution_id': contribution_id
    }), 200

@app.route('/api/train_model', methods=['POST'])
def train_model():
    data = request.json
    training_file = data.get('training_file')
    epochs = data.get('epochs', 10)
    batch_size = data.get('batch_size', 32)
    model_type = data.get('model_type', 'image')
    
    if not training_file:
        return jsonify({'error': 'No training file specified'}), 400
    
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], training_file)
    
    if not os.path.exists(filepath):
        return jsonify({'error': 'Training file not found'}), 404
    
    try:
        df = load_csv_data(filepath)
        
        if model_type == 'image':
            X, y = preprocess_image_data(df)
            input_shape = (64, 64, 3)
        else:
            X, y = preprocess_csv_features(df)
            input_shape = (X.shape[1],)
        
        num_classes = len(np.unique(y))
        
        split_idx = int(0.8 * len(X))
        X_train, X_val = X[:split_idx], X[split_idx:]
        y_train, y_val = y[:split_idx], y[split_idx:]
        
        if model_manager.model is None:
            if model_type == 'image':
                model_manager.create_model(input_shape, num_classes)
            else:
                model = keras.Sequential([
                    layers.Input(shape=input_shape),
                    layers.Dense(128, activation='relu'),
                    layers.Dropout(0.3),
                    layers.Dense(64, activation='relu'),
                    layers.Dropout(0.3),
                    layers.Dense(num_classes, activation='softmax')
                ])
                model.compile(
                    optimizer='adam',
                    loss='sparse_categorical_crossentropy',
                    metrics=['accuracy']
                )
                model_manager.model = model
        
        history = model_manager.model.fit(
            X_train, y_train,
            epochs=epochs,
            batch_size=batch_size,
            validation_data=(X_val, y_val),
            verbose=0
        )
        
        model_path = os.path.join(MODEL_FOLDER, f'model_{datetime.now().strftime("%Y%m%d_%H%M%S")}.h5')
        model_manager.save_model(model_path)
        
        training_record = {
            'timestamp': datetime.now().strftime('%Y%m%d_%H%M%S'),
            'training_file': training_file,
            'epochs': epochs,
            'batch_size': batch_size,
            'final_accuracy': float(history.history['accuracy'][-1]),
            'final_val_accuracy': float(history.history['val_accuracy'][-1]),
            'model_path': model_path
        }
        
        model_manager.training_history.append(training_record)
        
        return jsonify({
            'message': 'Model trained successfully',
            'training_record': training_record,
            'history': {
                'accuracy': [float(x) for x in history.history['accuracy']],
                'val_accuracy': [float(x) for x in history.history['val_accuracy']],
                'loss': [float(x) for x in history.history['loss']],
                'val_loss': [float(x) for x in history.history['val_loss']]
            }
        }), 200
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/retrain_with_contributions', methods=['POST'])
def retrain_with_contributions():
    data = request.json
    epochs = data.get('epochs', 5)
    batch_size = data.get('batch_size', 32)
    
    all_X = []
    all_y = []
    
    for contribution in model_manager.data_contributions:
        if contribution['status'] == 'uploaded':
            if contribution.get('type') == 'single_example':
                with open(contribution['filepath'], 'r') as f:
                    contrib_data = json.load(f)
                    all_X.append(contrib_data['data']['features'])
                    all_y.append(contrib_data['data']['label'])
            else:
                filepath = contribution['filepath']
                if filepath.endswith('.csv'):
                    df = load_csv_data(filepath)
                    X, y = preprocess_csv_features(df)
                    all_X.extend(X)
                    all_y.extend(y)
    
    if not all_X:
        return jsonify({'error': 'No contributions available for training'}), 400
    
    X = np.array(all_X)
    y = np.array(all_y)
    
    if model_manager.model is None:
        return jsonify({'error': 'No base model found. Train initial model first.'}), 400
    
    history = model_manager.model.fit(
        X, y,
        epochs=epochs,
        batch_size=batch_size,
        validation_split=0.2,
        verbose=0
    )
    
    model_path = os.path.join(MODEL_FOLDER, f'model_retrained_{datetime.now().strftime("%Y%m%d_%H%M%S")}.h5')
    model_manager.save_model(model_path)
    
    for contribution in model_manager.data_contributions:
        contribution['status'] = 'used_in_training'
    
    return jsonify({
        'message': 'Model retrained with community contributions',
        'contributions_used': len(model_manager.data_contributions),
        'final_accuracy': float(history.history['accuracy'][-1]),
        'model_path': model_path
    }), 200

@app.route('/api/predict', methods=['POST'])
def predict():
    if model_manager.model is None:
        return jsonify({'error': 'No trained model available'}), 400
    
    data = request.json
    features = data.get('features')
    
    if not features:
        return jsonify({'error': 'No features provided'}), 400
    
    try:
        X = np.array([features])
        predictions = model_manager.model.predict(X)
        predicted_class = int(np.argmax(predictions[0]))
        confidence = float(predictions[0][predicted_class])
        
        return jsonify({
            'predicted_class': predicted_class,
            'confidence': confidence,
            'all_probabilities': [float(p) for p in predictions[0]]
        }), 200
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/model_stats', methods=['GET'])
def model_stats():
    return jsonify({
        'model_exists': model_manager.model is not None,
        'total_contributions': len(model_manager.data_contributions),
        'training_history': model_manager.training_history,
        'contributions': model_manager.data_contributions
    }), 200

@app.route('/api/load_model', methods=['POST'])
def load_model():
    data = request.json
    model_name = data.get('model_name')
    
    if not model_name:
        return jsonify({'error': 'No model name provided'}), 400
    
    model_path = os.path.join(MODEL_FOLDER, model_name)
    
    if not os.path.exists(model_path):
        return jsonify({'error': 'Model not found'}), 404
    
    try:
        model_manager.load_model(model_path)
        return jsonify({'message': 'Model loaded successfully'}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)